  <div class="homepage-hero-module">
    <el-menu default-active="1"  mode="horizontal"
    background-color="#00acd3"
    active-text-color="#ffd04b"
    text-color="#ffffff"
    >
      <el-menu-item index="1"><a href="#"  style="text-decoration: none;">主页</a></el-menu-item>
      <el-menu-item index="2"><a href="/myblog/"  style="text-decoration: none;" target="_blank">博客</a></el-menu-item>
      <el-tooltip class="item" effect="dark" content="别着急，还未开发" placement="right">
        <el-menu-item index="3"><a href="#"  style="text-decoration: none;">简历</a></el-menu-item>
      </el-tooltip>
    </el-menu>
    <div class="video-container">

    <video :style="fixStyle" autoplay loop muted class="fillWidth" v-on:canplay="canplay">
      <source src="../assets/Sunset-Lapse.mp4" type="video/mp4"/>
    浏览器不支持 video 标签，建议升级浏览器。
    </video>
    </div>
    </div>
</template>

<script>
export default {
  name: 'Index',
  data () {
    return {
      vedioCanPlay: false,
      fixStyle: ''
    }
  },
  methods: {
    canplay () {
      this.vedioCanPlay = true
    }
  },
  mounted: function () { // 屏幕自适应
    window.onresize = () => {
      const windowWidth = document.body.clientWidth
      const windowHeight = document.body.clientHeight
      const windowAspectRatio = windowHeight / windowWidth
      let videoWidth
      let videoHeight
      if (windowAspectRatio < 0.5625) {
        videoWidth = windowWidth
        videoHeight = videoWidth * 0.5625
        this.fixStyle = {
          height: windowWidth * 0.5625 + 'px',
          width: windowWidth + 'px',
          'margin-bottom': (windowHeight - videoHeight) / 2 + 'px',
          'margin-left': 'initial'
        }
      } else {
        videoHeight = windowHeight
        videoWidth = videoHeight / 0.5625
        this.fixStyle = {
          height: windowHeight + 'px',
          width: windowHeight / 0.5625 + 'px',
          'margin-left': (windowWidth - videoWidth) / 2 + 'px',
          'margin-bottom': 'initial'
        }
      }
    }
    window.onresize()
  }

}
</script>

